-- IELTS — International English Language Testing System
UPDATE public.service_library
SET academy_metadata = '{"displayName":"IELTS — International English Language Testing System","shortDescription":"IDP India · Academic & General Training · Band 0–9 · 2-year validity","version":"v1.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated June 2026","learningLevel":"Intermediate","learningMinutes":18,"navBucket":"coaching","testFamily":"IELTS","policyAlert":{"active":true,"date":"June 2026","summary":"In India, book IELTS only via ieltsidpindia.com (IDP — sole distributor since July 2021). Verify exam fee and dates there before quoting. British Council India offers prep, not exam booking. Never guarantee a band score."},"alert":{"title":"Academic vs General Training","body":"University and most study visas require IELTS Academic. Canada PR and UK settlement typically require General Training (or Academic where stated). Confirm module before enrollment and exam registration."},"tags":[{"label":"Active test","variant":"success"},{"label":"Most accepted globally","variant":"neutral"},{"label":"Academic & GT","variant":"warning"},{"label":"Band scored 0–9","variant":"neutral"}],"chips":[{"label":"~2h 45m exam","variant":"neutral"},{"label":"2-year validity","variant":"success"},{"label":"IDP India booking","variant":"neutral"},{"label":"Exam fee separate","variant":"warning"}],"kpis":[{"label":"Exam duration","value":"~2h 45m","sub":"4 modules + speaking slot","tone":"primary"},{"label":"Exam fee (India)","value":"Verify IDP","sub":"Paid on ieltsidpindia.com","tone":"warning"},{"label":"Score validity","value":"2 years","sub":"From test date","tone":"success"},{"label":"Results","value":"3–13 days","sub":"CD-IELTS faster","tone":"violet"}],"about":[{"label":"Description","value":"Standardized English proficiency test measuring Listening, Reading, Writing, and Speaking. Jointly owned by British Council, IDP, and Cambridge. Used for study, work, and migration worldwide."},{"label":"Modules","value":"Listening (30 min) · Reading (60 min) · Writing (60 min) · Speaking (11–14 min). L/R/W on same day; Speaking may be same day or within 7 days before/after."},{"label":"Academic vs GT","value":"Academic: university & most study visas. General Training: Canada PR/citizenship, UK settlement, work migration. Same Listening & Speaking; different Reading & Writing.","warning":true},{"label":"Test authority (India)","value":"IDP IELTS India — book at ieltsidpindia.com only (sole distributor since July 2021). British Council India offers prep courses, not exam registration. FLC coaching fee is separate from exam fee."},{"label":"Delivery modes","value":"Paper-based, Computer-delivered (CD-IELTS), IELTS UKVI (SELT for UK visas), One Skill Retake (OSR) where available."},{"label":"India test centers","value":"Ahmedabad, Bengaluru, Chandigarh, Chennai, Delhi, Hyderabad, Kolkata, Mumbai, Pune, and other cities — verify current list on booking portal."},{"label":"After the test","value":"TRF (Test Report Form) issued; up to 5 free electronic sends to institutions. Hand TRF to admissions or visa team when target met."}],"compare":{"columns":["Country / pathway","Module","Minimum","Notes"],"rows":[{"label":"Canada — Express Entry (FSW)","values":["GT or Academic","CLB 7 = 6.0 each","TOEFL not accepted by IRCC"]},{"label":"Canada — Study permit (SDS)","values":["Academic","6.0 each","Verify IRCC SDS list"]},{"label":"Canada — Citizenship","values":["GT or Academic","CLB 4","Lower threshold"]},{"label":"Australia — Student (500)","values":["Academic","5.5–6.0+ (level-dependent)","CRICOS course level sets minimum"]},{"label":"Australia — Skilled (Competent)","values":["Academic","6.0 each","PTE also accepted"]},{"label":"UK — Student Route","values":["IELTS UKVI Academic","B2 (~5.5–6.5)","Standard IELTS may not suffice"]},{"label":"UK — Skilled Worker","values":["IELTS UKVI","B1","Check approved SELT list"]},{"label":"USA — F-1 admission","values":["Academic","Uni-specific","TOEFL more common; many accept IELTS"]},{"label":"New Zealand — SMC","values":["Academic","6.5 average","Verify immigration NZ"]},{"label":"NOT for Canada IRCC","values":["—","—","TOEFL, Duolingo, PTE Academic"]}]},"eligibility":[{"criterion":"Valid passport for registration and test day","met":true},{"criterion":"Correct module selected (Academic / GT / UKVI)","met":true},{"criterion":"Name on registration matches passport exactly","met":true},{"criterion":"Test date allows TRF before visa / uni deadline","met":true},{"criterion":"Minimum age — no upper limit; minors need guardian consent per center","met":true}],"testDayGuide":{"dos":["Arrive 30–45 minutes before reporting time","Bring the same valid passport used at registration","Confirm Academic vs GT and UKVI on confirmation email","Check headphones during Listening before sections start","Manage time in Writing — Task 2 carries more weight than Task 1","Speak naturally in Speaking — extend answers in Parts 2 and 3","Report audio or technical problems to invigilator immediately","Keep confirmation email and center address accessible"],"donts":["Do not bring phones, smartwatches, or bags into the test room","Do not bring passport photocopies — original only","Do not talk to other candidates during the test","Do not leave your seat without permission","Do not use memorized template essays word-for-word","Do not argue with the Speaking examiner about your score","Do not book Speaking on a conflicting day without checking schedule","Do not use correction fluid on paper tests where not permitted"],"checklist":["Passport + test confirmation","Correct test center and reporting time","Module type confirmed (Academic / GT / UKVI)","Counselor notified if first-time test taker (optional FLC briefing)","No prohibited items in pockets"]},"redFlagsBanner":"Wrong module, name mismatch, or mocks far below target — pause exam booking and fix before test day. Never guarantee a band score.","redFlags":[{"title":"GT student booked Academic (or reverse)","description":"Module does not match migration or study pathway.","fix":"Cancel and rebook correct module before test day","severity":"High"},{"title":"UK visa but standard IELTS booked","description":"UKVI SELT required for many UK visa routes.","fix":"Rebook IELTS UKVI at approved center","severity":"High"},{"title":"Name ≠ passport","description":"Registration name mismatch.","fix":"Contact IDP IELTS India to correct before test day","severity":"High"},{"title":"Mocks far below target","description":"Student not exam-ready.","fix":"Postpone exam; extra mocks and skill work","severity":"Common"},{"title":"Expired passport at booking","description":"Cannot test or TRF may be invalid.","fix":"Renew passport before registering","severity":"Very common"},{"title":"Guaranteed score promised","description":"Sales or counselor over-commitment.","fix":"Compliance issue — never guarantee bands","severity":"High"}],"faqs":[{"q":"Academic vs General Training — which one?","a":"Academic for university and most study visas. GT for Canada PR, citizenship, and many work/settlement routes. Confirm with destination country rules."},{"q":"Who pays the IELTS exam fee?","a":"In India, the student pays IDP IELTS India directly when registering on ieltsidpindia.com. FLC coaching fee is separate."},{"q":"CD-IELTS vs paper — any difference?","a":"Same content and scoring. CD-IELTS usually has faster results (3–5 days). Speaking is still face-to-face with examiner."},{"q":"Can Future Link guarantee band 7?","a":"No. We set targets from diagnostics and mocks. Outcomes depend on student effort, attendance, and exam performance."},{"q":"Is TOEFL accepted for Canada PR?","a":"No. IRCC accepts IELTS (GT or Academic per program) and CELPIP-General — not TOEFL or Duolingo for immigration."},{"q":"What is IELTS UKVI?","a":"Secure English Language Test format required for many UK visa applications. Book UKVI at an approved SELT center — standard IELTS may not count."},{"q":"How long is IELTS valid?","a":"Two years from the test date for most immigration and university purposes."},{"q":"What is One Skill Retake (OSR)?","a":"Retake one section within 60 days of a full test where offered. Confirm eligibility on ielts.org before advising."},{"q":"How many free TRF sends?","a":"Up to five institutions included; additional sends may incur a fee."},{"q":"Speaking on a different day — is that normal?","a":"Yes. Speaking may be scheduled up to 7 days before or after L/R/W."}],"compliance":["Never guarantee an IELTS band score","Separate coaching fee from exam registration fee on all quotes","Verify exam fee on ieltsidpindia.com before quoting","Confirm Academic vs GT and UKVI before enrollment and booking","Record diagnostic, mock scores, and TRF on client file"],"proTips":["Use CLB mapping for every Canada lead — counselors must know 6.0 = CLB 7","Book exam only after two mocks within 0.5 band of target","For UK routes, check UKVI requirement before any booking","Brief first-time test takers using the Test day guide tab","Link TRF to visa/admissions file as soon as results arrive"],"postApproval":["Collect official TRF when released","Upload scores to client CRM record","Notify admissions or visa team with breakdown L/R/W/S","Plan retake, OSR, or booster if below target"],"performance":{"ourRate":84,"industryRate":68,"stats":[{"label":"FLC enrollments (IELTS)","value":"380+"},{"label":"Hit agreed target","value":"84%"},{"label":"Retake / OSR","value":"16%"}]},"approvalFactors":[{"label":"Client satisfaction","ours":88,"benchmark":74},{"label":"Score improvement","ours":82,"benchmark":68},{"label":"Test pass / target met","ours":84,"benchmark":70}],"timeline":[{"weeks":"1","title":"Diagnostic, target band, module confirmation"},{"weeks":"2–8","title":"Coaching, homework, skill drills, speaking mocks"},{"weeks":"6–8","title":"Full mocks under exam conditions"},{"weeks":"8–10","title":"Exam registration, test day briefing, TRF follow-up"}],"relatedServices":[{"label":"IELTS Academic Regular (with books)","libraryId":"b2000001-0001-4000-8000-000000000072"},{"label":"IELTS Academic Crash Course","libraryId":"b2000001-0001-4000-8000-000000000073"},{"label":"IELTS General Regular (with books)","libraryId":"b2000001-0001-4000-8000-000000000074"},{"label":"Canada — Express Entry PR","libraryId":"b2000001-0001-4000-8000-000000000013"},{"label":"Canada — Study Permit","libraryId":"c35e6051-f40f-47bf-9cac-0a386c47a336"}],"changelog":[{"version":"v1.0","date":"June 2026","author":"Service Library","summary":"Initial IELTS test reference — acceptance matrix, test day guide, module samples."}],"staffNotes":[{"author":"Coaching team","date":"June 2026","text":"This is the shared IELTS test reference. Program-specific batches (Regular, Crash, GT) link here for official test facts."}],"resources":[{"title":"IELTS — Official site","url":"https://www.ielts.org/","description":"Format, Academic vs GT, OSR"},{"title":"IDP IELTS India — Book test","url":"https://www.ieltsidpindia.com/","description":"Sole IELTS booking channel in India — fees, dates, centers"},{"title":"British Council India — IELTS prep","url":"https://www.britishcouncil.in/exam/ielts/faqs","description":"Prep courses only — BC does not deliver IELTS tests in India"},{"title":"IRCC — Language requirements","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/immigrate-canada/express-entry/documents/language-requirements.html","description":"CLB and accepted tests"},{"title":"UKVI — Approved SELT tests","url":"https://www.gov.uk/guidance/prove-your-english-language-abilities-with-a-secure-english-language-test-selt","description":"UK visa English tests"}],"donts":{"dos":["Run diagnostic before quoting timeline","Confirm Academic vs GT for every lead","Brief students with test day do''s before exam","Keep coaching and exam fees separate on quotes","Track mocks weekly — not just overall average"],"donts":["Guarantee a band score","Quote exam fee without verifying on ieltsidpindia.com","Book exam before mocks support target","Send GT student to Academic exam without confirmation","Skip UKVI check for UK visa clients"],"mistakes":["Target 7.0 from diagnostic 5.0 in 4 weeks","Wrong name on registration vs passport","Standard IELTS for UK Student Route when UKVI required","Visa team not updated when TRF arrives"]},"sampleDocs":[{"title":"Sample Listening — Section 1 (form completion)","description":"FLC specimen: short conversation, 5 questions. For classroom or counselor demo.","docKind":"listening_sample","url":"/specimens/coaching/ielts-samples/listening.html","mimeType":"text/html"},{"title":"Sample Reading — Academic passage","description":"One passage excerpt with True/False/Not Given questions.","docKind":"reading_sample","url":"/specimens/coaching/ielts-samples/reading.html","mimeType":"text/html"},{"title":"Sample Writing — Task 1 (Academic)","description":"Bar chart description prompt with band 6 vs 7 outline.","docKind":"writing_sample","url":"/specimens/coaching/ielts-samples/writing.html","mimeType":"text/html"},{"title":"Sample Speaking — Part 2 cue card","description":"Cue card topic with structure for a 2-minute response.","docKind":"speaking_sample","url":"/specimens/coaching/ielts-samples/speaking.html","mimeType":"text/html"},{"title":"Test day checklist (printable)","description":"Passport, timing, module confirm — give to every first-time test taker.","docKind":"test_day","url":"/specimens/coaching/ielts-test-day-checklist.html","mimeType":"text/html"},{"title":"Enrollment checklist — IELTS Academic Regular","description":"Counselor enrollment and delivery checklist.","docKind":"enrollment","url":"/specimens/coaching/ielts-academic-regular-checklist.html","mimeType":"text/html"}],"quiz":[{"question":"IELTS Academic is typically required for:","options":["University study visas","Canada citizenship only","Driving licence","Tourist visas only"],"correctIndex":0,"explanation":"Universities and most study pathways require Academic.","level":1},{"question":"IELTS score validity is generally:","options":["6 months","1 year","2 years","Lifetime"],"correctIndex":2,"explanation":"Two years from test date for most uses.","level":1},{"question":"For Canada Express Entry FSW, CLB 7 equals approximately:","options":["IELTS 5.0 each","IELTS 6.0 each","IELTS 7.5 each","IELTS 8.0 each"],"correctIndex":1,"explanation":"CLB 7 maps to IELTS 6.0 in each skill.","level":2},{"question":"TOEFL iBT is accepted by IRCC for Canadian PR:","options":["Yes, always","No","Only for Quebec","Only with job offer"],"correctIndex":1,"explanation":"IRCC does not accept TOEFL for immigration.","level":2},{"question":"On test day, the student must bring:","options":["Passport photocopy","Same valid passport as registration","Aadhaar card","Driving licence"],"correctIndex":1,"explanation":"Original passport matching registration.","level":1},{"question":"Which item is prohibited in the IELTS test room?","options":["Transparent water bottle (if allowed)","Mobile phone","Passport","Confirmation email printout (before check-in)"],"correctIndex":1,"explanation":"Phones and smartwatches must be stored outside.","level":1},{"question":"UK Student Route often requires:","options":["Standard IELTS only","IELTS UKVI Academic","No English test","CELPIP-General"],"correctIndex":1,"explanation":"Many UK visas require UKVI SELT format.","level":2},{"question":"Counselors must never:","options":["Track mock scores","Guarantee band 7","Confirm module type","Link TRF to visa file"],"correctIndex":1,"explanation":"Band guarantees are prohibited.","level":1},{"question":"IELTS exam fee in India is paid to:","options":["Future Link only","IDP IELTS India by student","University","Embassy"],"correctIndex":1,"explanation":"Book and pay on ieltsidpindia.com — separate from coaching fee.","level":1},{"question":"Speaking test duration is approximately:","options":["5 minutes","11–14 minutes","30 minutes","60 minutes"],"correctIndex":1,"explanation":"Speaking is 11–14 minutes face-to-face.","level":1},{"question":"CD-IELTS results typically arrive in:","options":["Same day","3–5 days","8 weeks","6 months"],"correctIndex":1,"explanation":"Computer-delivered tests usually score faster.","level":2},{"question":"General Training is commonly used for:","options":["Canada PR and citizenship","PhD research admission only","Medical licensing only","Internal FLC diagnostic"],"correctIndex":0,"explanation":"GT is standard for many migration pathways.","level":2},{"question":"The correct order on test day for L/R/W is:","options":["Writing → Reading → Listening","Listening → Reading → Writing","Reading → Listening → Writing","Random"],"correctIndex":1,"explanation":"Fixed order: Listening, Reading, Writing.","level":2},{"question":"One Skill Retake (OSR) allows:","options":["Retaking one section within 60 days","Free unlimited retakes","Skipping Speaking","Changing Academic to GT"],"correctIndex":0,"explanation":"OSR retakes one section where offered.","level":3},{"question":"Before booking the exam, FLC policy recommends:","options":["Two mocks within 0.5 of target","No mocks needed","Guarantee band 8","Book earliest date always"],"correctIndex":0,"explanation":"Readiness based on mock performance.","level":2}]}'::jsonb, updated_at = now()
