SET academy_metadata = '{"displayName":"IELTS Academic Regular (with books)","shortDescription":"IDP India · Academic module · 8–10 week regular batch · Books included","version":"v1.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated June 2026","learningLevel":"Intermediate","learningMinutes":12,"navBucket":"coaching","policyAlert":{"active":true,"date":"June 2026","summary":"In India, book IELTS only via ieltsidpindia.com (IDP). Verify exam fee and dates there before quoting. Academic vs General Training must match student goal. Never guarantee a band score."},"alert":{"title":"Academic module only","body":"University and student visa pathways require IELTS Academic. Confirm module before enrollment — not General Training."},"tags":[{"label":"Active program","variant":"success"},{"label":"Books included","variant":"neutral"},{"label":"8–10 weeks","variant":"neutral"},{"label":"Academic module","variant":"warning"}],"chips":[{"label":"Regular batch","variant":"success"},{"label":"4+ full mocks","variant":"neutral"},{"label":"Target band agreed","variant":"warning"},{"label":"Exam fee separate","variant":"neutral"}],"kpis":[{"label":"Course duration","value":"8–10w","sub":"Regular batch","tone":"primary"},{"label":"IELTS exam fee","value":"See IDP India","sub":"Paid on ieltsidpindia.com","tone":"warning"},{"label":"Target achievement","value":"82%","sub":"Students hitting agreed target","tone":"success"},{"label":"Enrollment docs","value":"6","sub":"Agreement + diagnostic","tone":"violet"},{"label":"Course fee","value":"See fee tab","sub":"Books included","tone":"primary"}],"about":[{"label":"Description","value":"Structured IELTS Academic preparation — Listening, Reading, Writing, Speaking — with course books, trainer-led classes, homework, and full mock tests."},{"label":"Ideal for","value":"Students targeting band 6.0–7.5 for study abroad, PR pathways requiring Academic, or university conditional offers."},{"label":"Delivery","value":"Regula